/**
 * Checks if a number is prime.
 * @param n The number to check.
 * @returns True if n is prime, false otherwise.
 */
function isPrime(n: number): boolean {
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 === 0 || n % 3 === 0) return false;
    for (let i = 5; i * i <= n; i = i + 6) {
        if (n % i === 0 || n % (i + 2) === 0) return false;
    }
    return true;
}

/**
 * Finds the smallest number >= startNum that satisfies the condition (prime or composite).
 * @param startNum The starting number.
 * @param isRequiredPrime True if the target must be prime, false if it must be non-prime.
 * @returns The minimum increments needed.
 */
function findMinIncrements(startNum: number, isRequiredPrime: boolean): number {
    let currentNum = startNum;
    let increments = 0;

    while (true) {
        const isP = isPrime(currentNum);
        const matches = isRequiredPrime ? isP : !isP;

        if (matches) {
            return increments;
        }

        // If it doesn't match, increment and continue searching
        currentNum += 1;
        increments += 1;
    }
}

function solve(nums: number[]): number {
    let totalOperations = 0;
    const n = nums.length;

    for (let i = 0; i < n; i++) {
        const startNum = nums[i];
        const isEvenIndex = i % 2 === 0;

        if (isEvenIndex) {
            // Even index: must be prime
            const increments = findMinIncrements(startNum, true);
            totalOperations += increments;
        } else {
            // Odd index: must be non-prime (composite or 1)
            // Note: 1 is non-prime by definition (not greater than 1 or only divisible by 1 and itself)
            const increments = findMinIncrements(startNum, false);
            totalOperations += increments;
        }
    }

    return totalOperations;
}
